const userRow = $json || {};
const originalItems = $items("Code - Normalize Telegram Update");
const original = originalItems?.[0]?.json || {};
const isAuthorized = !!userRow.telegram_id;

return [
  {
    json: {
      ...original,
      auth_user: userRow,
      telegram_id: userRow.telegram_id || "",
      authorized_first_name: userRow.first_name || "",
      authorized_last_name: userRow.last_name || "",
      authorized_username: userRow.username || "",
      authorized_role: userRow.role || "",
      is_authorized: isAuthorized
    }
  }
];

const data = $json.callback_data || "";
const chat_id = $json.chat_id || "";
const callback_query_id = $json.callback_query_id || "";
const clicked_by = $json.user_name || "Unknown";
const telegram_user_id = $json.user_id || "";

let action = "";
let decision = "";
let order_id = "";
let document_id = "";
let conversation_id = "";

if (data.startsWith("approve_")) {
  action = "process_order_approval_reply";
  decision = "approve";
  order_id = data.replace("approve_", "").trim().toUpperCase();
} else if (data.startsWith("reject_")) {
  action = "process_order_approval_reply";
  decision = "reject";
  order_id = data.replace("reject_", "").trim().toUpperCase();
} else if (data.startsWith("quote_send|") || data.startsWith("quote_cancel|")) {
  const parts = data.split("|");
  action = "route_document_send_callback";
  order_id = (parts[1] || "").trim().toUpperCase();
  document_id = (parts[2] || "").trim();
  conversation_id = (parts[3] || "").trim();
}

if (!action) {
  action = "invalid_callback";
}

return [
  {
    json: {
      action,
      decision,
      order_id,
      document_id,
      conversation_id,
      callback_data: data,
      chat_id: String(chat_id),
      callback_query_id,
      changed_by: clicked_by,
      trigger_source: "Telegram Button",
      clicked_by,
      telegram_user_id: String(telegram_user_id),
      decision_method: "Button"
    }
  }
];

const update = $json;
const message = update.message || {};
const callback = update.callback_query || {};
const callbackMessage = callback.message || {};
const from = callback.from || message.from || {};
const chat = callbackMessage.chat || message.chat || {};
const updateType = callback.id ? "callback_query" : (message.message_id ? "message" : "unknown");

return [
  {
    json: {
      update_type: updateType,
      user_id: String(from.id || ""),
      user_name: from.first_name || "Unknown",
      chat_id: String(chat.id || from.id || ""),
      message_text: (message.text || "").trim(),
      message_id: message.message_id || callbackMessage.message_id || "",
      callback_query_id: callback.id || "",
      callback_data: callback.data || "",
      channel: "TELEGRAM",
      timestamp: new Date().toISOString(),
      raw_update: update
    }
  }
];

